SELECT 
FROM sys_salary s
WHERE s.emp_id = #{empId} AND s.salary_month = #{salaryMonth}

SELECT ,
       e.emp_name, e.emp_no, d.dept_name
FROM sys_salary s
LEFT JOIN sys_emp e ON s.emp_id = e.id
LEFT JOIN sys_dept d ON e.dept_id = d.id


        AND s.emp_id = #{empId}


        AND e.emp_name LIKE CONCAT('%', #{empName}, '%')


        AND s.salary_month = #{salaryMonth}


        AND s.status = #{status}


ORDER BY s.salary_month DESC, d.id, e.id

